package com.google.gson.internal;
import java.lang.reflect.AccessibleObject;
import java.lang.reflect.Method;
import java.util.List;
import com.google.gson.ReflectionAccessFilter;
import com.google.gson.ReflectionAccessFilter.FilterResult;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class ReflectionAccessFilterHelperTest {

  @Test
  void testIsAnyPlatformType_withAndroidType() {
    // Use a class with a name starting with "android."
    Class<?> androidClass = AndroidDummy.class;
    assertTrue(ReflectionAccessFilterHelper.isAnyPlatformType(androidClass));
  }

  @Test
  void testIsAnyPlatformType_withKotlinPackage() {
    Class<?> kotlinClass = KotlinDummy.class;
    assertTrue(ReflectionAccessFilterHelper.isAnyPlatformType(kotlinClass));
  }

  @Test
  void testIsAnyPlatformType_withKotlinxPackage() {
    Class<?> kotlinxClass = KtxDummy.class;
    assertTrue(ReflectionAccessFilterHelper.isAnyPlatformType(kotlinxClass));
  }

  @Test
  void testIsAnyPlatformType_withScalaPackage() {
    Class<?> scalaClass = ScalaDummy.class;
    assertTrue(ReflectionAccessFilterHelper.isAnyPlatformType(scalaClass));
  }

  @Test
  void testIsAnyPlatformType_withOtherClass() {
    Class<?> otherClass = NonPlatformDummy.class;
    assertFalse(ReflectionAccessFilterHelper.isAnyPlatformType(otherClass));
  }

  // Dummy classes to simulate package names by overriding getName()
  static class AndroidDummy extends ClassNameOverride {
    @Override
    public String getName() {
      return "android.dummy.Class";
    }
  }

  static class KotlinDummy extends ClassNameOverride {
    @Override
    public String getName() {
      return "kotlin.dummy.Class";
    }
  }

  static class KtxDummy extends ClassNameOverride {
    @Override
    public String getName() {
      return "kotlinx.dummy.Class";
    }
  }

  static class ScalaDummy extends ClassNameOverride {
    @Override
    public String getName() {
      return "scala.dummy.Class";
    }
  }

  static class NonPlatformDummy extends ClassNameOverride {
    @Override
    public String getName() {
      return "java.lang.String"; // does not start with any platform prefix
    }
  }

  /**
   * Trick to override getName() for testing.
   * We extend Class and override getName() via a proxy class.
   * Since Class is final, we cannot extend it directly.
   * So we create a proxy class that implements Class<?> interface methods we need.
   * However, since ReflectionAccessFilterHelper.isAnyPlatformType calls c.getName(),
   * which is final in Class, we cannot override it directly.
   * 
   * Instead, we create a dynamic proxy class that implements Class<?> with a getName() method returning desired string.
   * But Class is final and cannot be proxied.
   * 
   * Therefore, we use a custom Class subclass via a trick: 
   * We create a dummy class in the desired package by using a custom ClassLoader.
   * 
   * For simplicity here, we create a minimal custom ClassLoader to define classes with desired package names.
